set-variable.value:
@{
            string deploymentName = "unknown";
            try
            {
                var body = context.Request.Body.As<JObject>(preserveContent: true);
                if (body != null && body["model"] != null)
                {
                    deploymentName = body["model"].Value<string>();
                }
            }
            catch { }
            return deploymentName;
        }

return-response.set-body:
@{
                        var deploymentName = (string)context.Variables["deploymentName"];
                        return new JObject(
                            new JProperty("error", new JObject(
                                new JProperty("code", "InsufficientPermissions"),
                                new JProperty("message", string.Format("Access denied. Required role '{0}' not found in JWT token.", deploymentName))
                            ))
                        ).ToString();
                    }

send-request.set-url:
@{
                                var objectId = (string)context.Variables["caller-objectid"];
                                var filter = "?$filter=id eq '" + objectId + "'";
                                var select = "$select=displayName";
                                return "https://graph.microsoft.com/beta/servicePrincipals" + filter + "&" + select;
                            }

set-variable.value:
@{
                            try
                            {
                                var response = (IResponse)context.Variables["graph-response"];
                                var body = response.Body.As<JObject>();
                                var value = body["value"];
                                if (value != null && value.HasValues)
                                {
                                    return value[0]["displayName"].ToString();
                                }
                            }
                            catch { }
                            return "Unknown";
                        }

@{
            try {
                var mapping = Newtonsoft.Json.Linq.JObject.Parse((string)context.Variables["quota-mapping"]);
                var oid = (string)context.Variables["caller-objectid"];
                var entry = mapping[oid] ?? mapping["default"];
                if (entry != null) { return entry["tpm"]?.ToString() ?? "200"; }
            } catch { }
            return "200";
        }

@{
            try {
                var mapping = Newtonsoft.Json.Linq.JObject.Parse((string)context.Variables["quota-mapping"]);
                var oid = (string)context.Variables["caller-objectid"];
                var entry = mapping[oid] ?? mapping["default"];
                if (entry != null) { return entry["monthlyQuota"]?.ToString() ?? "500000"; }
            } catch { }
            return "500000";
        }

when.set-body:
@{
                    var body = context.Request.Body.As<JObject>(preserveContent: true);
                    if (body["stream_options"] == null) { body["stream_options"] = new JObject(); }
                    ((JObject)body["stream_options"])["include_usage"] = true;
                    return body.ToString();
                }

on-error.trace:
@{
            return string.Format("Error capturing AI usage: {0}", context.LastError.Message);
        }
